sql:
SELECT category_id, category_name, category_description
FROM demographic_categories
WHERE category_name IN ('Family Structures', 'Household Types');

SELECT COUNT(*) AS total_definitions, definition_text
FROM definitions
WHERE definition_text LIKE '%female%';

SELECT margin_value
FROM error_margins
WHERE margin_id = 1;

SELECT source_name, source_description, source_url
FROM data_sources
WHERE source_id BETWEEN 1 AND 5;

SELECT unit_name
FROM units_of_measure
WHERE unit_name LIKE 'C%';

external_knowledge:
A handful of times = more than five times;
US Census site = sites related to USCENSUS.GOV;
Researchers = users with the role specified as 'researcher';
Start of last year = January 1, 2023.

sql:
SELECT unit_level_name, unit_level_description
FROM unit_levels
WHERE unit_level_id = 1;

external_knowledge:
- 'beacon' metaphorically refers to data sources;
- 'lighthouse' metaphorically represents a source of guidance or information;
- 'curious eyes' refers to viewers or individuals who access the data;
- 'top 10 beacons of curiosity' refers to the top 10 data sources based on the number of views;
- 'attracting the most curious eyes' means the data source has been viewed the most frequently.
